Popularity is measured by the number of likes received; 
 The 'most liked characters' refers to the top 10 characters with the most likes; 
 'Prevalent traits' means the traits that appear most frequently.

sql:
SELECT c.name, c.age, c.origin, c.description, ci.image_path
FROM characters c
LEFT JOIN character_images ci ON c.character_id = ci.character_id AND ci.is_main_image = 1;

SELECT GROUP_CONCAT(name, ', ') AS Characters
FROM (
    SELECT name
    FROM characters
    WHERE age > (SELECT AVG(age) FROM characters)
);

SELECT characters.name AS character_name, franchises.name AS franchise_name
FROM characters
JOIN franchises ON characters.franchise_id = franchises.franchise_id;

SELECT character_id_1, COUNT(*) AS total_interactions
FROM character_interactions
GROUP BY character_id_1;

SELECT character_history.event_date, character_history.event_type, character_history.details
FROM character_history
WHERE character_history.character_id = 0;

SELECT characters.name, characters.character_id, character_likes.like_name, character_likes.category_id
FROM characters
INNER JOIN character_likes ON characters.character_id = character_likes.character_id;
